1	pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
2	    const object = JSValue.createEmptyObject(globalThis, 2);
3	    object.put(
4	        globalThis,
5	        ZigString.static("parse"),
6	        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
7	    );
8	    object.put(
9	        globalThis,
10	        ZigString.static("stringify"),
11	        jsc.JSFunction.create(globalThis, "stringify", stringify, 3, .{}),
12	    );
13	    return object;
14	}
15	
16	pub fn stringify(
17	    global: *jsc.JSGlobalObject,
18	    callFrame: *jsc.CallFrame,
19	) bun.JSError!jsc.JSValue {
20	    const value, const replacer, const space_value = callFrame.argumentsAsArray(3);
21	
22	    value.ensureStillAlive();
23	
24	    if (value.isUndefined() or value.isSymbol() or value.isFunction()) {
25	        return .js_undefined;
26	    }
27	
28	    if (!replacer.isUndefinedOrNull()) {
29	        return global.throw("JSON5.stringify does not support the replacer argument", .{});
30	    }
31	
32	    var stringifier: Stringifier = try .init(global, space_value);
33	    defer stringifier.deinit();
34	
35	    stringifier.stringifyValue(global, value) catch |err| return switch (err) {
36	        error.OutOfMemory, error.JSError, error.JSTerminated => |js_err| js_err,
37	        error.StackOverflow => global.throwStackOverflow(),
38	    };
39	
40	    return stringifier.builder.toString(global);
41	}
42	
43	pub fn parse(
44	    global: *jsc.JSGlobalObject,
45	    callFrame: *jsc.CallFrame,
46	) bun.JSError!jsc.JSValue {
47	    var arena: bun.ArenaAllocator = .init(bun.default_allocator);
48	    defer arena.deinit();
49	    const allocator = arena.allocator();
50	
51	    var ast_memory_allocator = bun.handleOom(allocator.create(ast.ASTMemoryAllocator));
52	    var ast_scope = ast_memory_allocator.enter(allocator);
53	    defer ast_scope.exit();
54	
55	    const input_value = callFrame.argument(0);
56	
57	    if (input_value.isEmptyOrUndefinedOrNull()) {
58	        return global.throwInvalidArguments("Expected a string to parse", .{});
59	    }
60	
61	    const input: jsc.Node.BlobOrStringOrBuffer =
62	        try jsc.Node.BlobOrStringOrBuffer.fromJS(global, allocator, input_value) orelse input: {
63	            var str = try input_value.toBunString(global);
64	            defer str.deref();
65	            break :input .{ .string_or_buffer = .{ .string = str.toSlice(allocator) } };
66	        };
67	    defer input.deinit();
68	
69	    var log = logger.Log.init(bun.default_allocator);
70	    defer log.deinit();
71	
72	    const source = &logger.Source.initPathString("input.json5", input.slice());
73	
74	    const root = json5.JSON5Parser.parse(source, &log, allocator) catch |err| return switch (err) {
75	        error.OutOfMemory => |oom| oom,
76	        error.StackOverflow => global.throwStackOverflow(),
77	        else => {
78	            if (log.msgs.items.len > 0) {
79	                const first_msg = log.msgs.items[0];
80	                return global.throwValue(global.createSyntaxErrorInstance(
81	                    "JSON5 Parse error: {s}",
82	                    .{first_msg.data.text},
83	                ));
84	            }
85	            return global.throwValue(global.createSyntaxErrorInstance(
86	                "JSON5 Parse error: Unable to parse JSON5 string",
87	                .{},
88	            ));
89	        },
90	    };
91	
92	    return exprToJS(root, global);
93	}
