105	    pub const Formatter = struct {
106	        pub fn format(_: Formatter, writer: *std.Io.Writer) !void {
107	            const fields = comptime brk: {
108	                const info: std.builtin.Type = @typeInfo(Features);
109	                var buffer: [info.@"struct".decls.len][]const u8 = .{""} ** info.@"struct".decls.len;
110	                var count: usize = 0;
111	                for (info.@"struct".decls) |decl| {
112	                    var f = &@field(Features, decl.name);
113	                    _ = &f;
114	                    const Field = @TypeOf(f);
115	                    const FieldT: std.builtin.Type = @typeInfo(Field);
116	                    if (FieldT.pointer.child != usize) continue;
117	                    buffer[count] = decl.name;
118	                    count += 1;
119	                }
120	
121	                break :brk buffer[0..count];
122	            };
123	
124	            var is_first_feature = true;
125	            inline for (fields) |field| {
126	                const count = @field(Features, field);
127	                if (count > 0) {
128	                    if (is_first_feature) {
129	                        try writer.writeAll("Features: ");
130	                        is_first_feature = false;
131	                    }
132	                    try writer.writeAll(field);
133	                    if (count > 1) {
134	                        try writer.print("({d}) ", .{count});
135	                    } else {
136	                        try writer.writeAll(" ");
137	                    }
138	                }
139	            }
140	            if (!is_first_feature) {
141	                try writer.writeAll("\n");
142	            }
143	
144	            var builtins = builtin_modules.iterator();
145	            if (builtins.next()) |first| {
146	                try writer.writeAll("Builtins: \"");
147	                try writer.writeAll(@tagName(first));
148	                try writer.writeAll("\" ");
149	
150	                while (builtins.next()) |key| {
151	                    try writer.writeAll("\"");
152	                    try writer.writeAll(@tagName(key));
153	                    try writer.writeAll("\" ");
154	                }
155	
156	                try writer.writeAll("\n");
157	            }
158	        }
159	    };
160	};
