180	    // ── Scanner ──
181	
182	    /// Returns the byte at the current position, or 0 if at EOF.
183	    /// All source access in scan() goes through this to avoid bounds checks.
184	    fn peek(self: *const JSON5Parser) u8 {
185	        if (self.pos < self.source.len) return self.source[self.pos];
186	        return 0;
187	    }
188	
189	    fn scan(self: *JSON5Parser) ParseError!void {
190	        self.token.data = next: switch (self.peek()) {
191	            0 => {
192	                self.token.loc = .{ .start = @intCast(self.pos) };
193	                break :next .eof;
194	            },
195	            // Whitespace — skip without setting loc
196	            '\t', '\n', '\r', ' ', 0x0B, 0x0C => {
197	                self.pos += 1;
198	                continue :next self.peek();
199	            },
200	            // Structural
201	            '{' => {
202	                self.token.loc = .{ .start = @intCast(self.pos) };
203	                self.pos += 1;
204	                break :next .left_brace;
205	            },
206	            '}' => {
207	                self.token.loc = .{ .start = @intCast(self.pos) };
208	                self.pos += 1;
209	                break :next .right_brace;
210	            },
211	            '[' => {
212	                self.token.loc = .{ .start = @intCast(self.pos) };
213	                self.pos += 1;
214	                break :next .left_bracket;
215	            },
216	            ']' => {
217	                self.token.loc = .{ .start = @intCast(self.pos) };
218	                self.pos += 1;
219	                break :next .right_bracket;
220	            },
221	            ':' => {
222	                self.token.loc = .{ .start = @intCast(self.pos) };
223	                self.pos += 1;
224	                break :next .colon;
225	            },
226	            ',' => {
227	                self.token.loc = .{ .start = @intCast(self.pos) };
228	                self.pos += 1;
229	                break :next .comma;
230	            },
231	            '+' => {
232	                self.token.loc = .{ .start = @intCast(self.pos) };
233	                self.pos += 1;
234	                break :next .{ .number = try self.scanSignedValue(false) };
235	            },
236	            '-' => {
237	                self.token.loc = .{ .start = @intCast(self.pos) };
238	                self.pos += 1;
239	                break :next .{ .number = try self.scanSignedValue(true) };
240	            },
241	            // Strings
242	            '"', '\'' => {
243	                self.token.loc = .{ .start = @intCast(self.pos) };
244	                break :next .{ .string = try self.scanString() };
245	            },
246	            // Numbers
247	            '0'...'9', '.' => {
248	                self.token.loc = .{ .start = @intCast(self.pos) };
249	                break :next .{ .number = try self.scanNumber() };
250	            },
251	            // Comments — skip without setting loc
252	            '/' => {
253	                const n = if (self.pos + 1 < self.source.len) self.source[self.pos + 1] else 0;
254	                if (n == '/') {
255	                    self.pos += 2;
256	                    self.skipToEndOfLine();
257	                    continue :next self.peek();
258	                } else if (n == '*') {
259	                    self.pos += 2;
260	                    try self.skipBlockComment();
261	                    continue :next self.peek();
262	                }
263	                return error.UnexpectedCharacter;
264	            },
265	            else => |c| {
266	                if (c == 't') {
267	                    self.token.loc = .{ .start = @intCast(self.pos) };
268	                    break :next if (self.scanKeyword("true")) .{ .boolean = true } else .{ .identifier = try self.scanIdentifier() };
269	                } else if (c == 'f') {
270	                    self.token.loc = .{ .start = @intCast(self.pos) };
271	                    break :next if (self.scanKeyword("false")) .{ .boolean = false } else .{ .identifier = try self.scanIdentifier() };
272	                } else if (c == 'n') {
273	                    self.token.loc = .{ .start = @intCast(self.pos) };
274	                    break :next if (self.scanKeyword("null")) .null else .{ .identifier = try self.scanIdentifier() };
275	                } else if ((c >= 'a' and c <= 'z') or (c >= 'A' and c <= 'Z') or c == '_' or c == '$' or c == '\\') {
276	                    self.token.loc = .{ .start = @intCast(self.pos) };
277	                    break :next .{ .identifier = try self.scanIdentifier() };
278	                } else if (c >= 0x80) {
279	                    // Multi-byte: check whitespace first, then identifier
280	                    const mb = self.multiByteWhitespace();
281	                    if (mb > 0) {
282	                        self.pos += mb;
283	                        continue :next self.peek();
284	                    }
285	                    self.token.loc = .{ .start = @intCast(self.pos) };
286	                    const cp = self.readCodepoint() orelse {
287	                        return error.UnexpectedCharacter;
288	                    };
289	                    if (identifier.isIdentifierStart(cp.cp)) {
290	                        break :next .{ .identifier = try self.scanIdentifier() };
291	                    } else {
292	                        return error.UnexpectedCharacter;
293	                    }
294	                } else {
295	                    return error.UnexpectedCharacter;
296	                }
297	            },
298	        };
299	    }

