885	                if (base == .oct or (e and base == .dec)) {
886	                    offset.* = i;
887	                    return false;
888	                }
889	                e = true;
890	                i += 1;
891	                if (i < str.length()) {
892	                    continue :next str.charAt(i);
893	                }
894	                return true;
