133	        pub const Name = union(AnchorOrigin) {
134	            // only one root anchor is possible
135	            root,
136	            array_item: usize,
137	            prop_value: struct {
138	                prop_name: String,
139	                // added after the name
140	                counter: usize,
141	            },
142	        };
143	    };
