147	        // always rename anchors named "root" to avoid collision with
148	        // root anchor/alias
149	        try prop_names.put("root", 0);
150	
151	        return .{
152	            .stack_check = .init(),
153	            .builder = .init(),
154	            .indent = 0,
155	            .known_collections = .init(allocator),
156	            .array_item_counter = 0,
157	            .prop_names = prop_names,
