/// Self-contained INI parser that returns a js_ast.Expr tree.
/// Does NOT depend on src/ini.zig (the internal package-manager parser).
///
/// Supported syntax:
///   [section]          section header
///   [a.b.c]            dotted section names (creates nested objects)
///   key = value        key/value assignment
///   key: value         colon-style assignment
///   ; comment          semicolon comment
///   # comment          hash comment
///   "quoted value"     double-quoted string (quotes stripped)
///   'quoted value'     single-quoted string (quotes stripped)
///
/// Unquoted value coercion:
///   true / false       boolean
///   null               null
///   integer            number (e.g. 42)
///   float              number (e.g. 3.14)
///   other              string

pub const INI = struct {
    pub fn parse(source_: *const logger.Source, allocator: std.mem.Allocator) !Expr {
        if (source_.contents.len == 0) {
            return Expr.init(E.Object, E.Object{}, logger.Loc.Empty);
        }
        var p: Parser = .{ .allocator = allocator, .input = source_.contents };
        return p.run();
    }
};

const Parser = struct {
    allocator: std.mem.Allocator,
    input: []const u8,
    pos: usize = 0,

    fn run(p: *Parser) !Expr {
        const root_expr = Expr.init(E.Object, E.Object{}, logger.Loc.Empty);
        var current: *E.Object = root_expr.data.e_object;

        while (p.pos < p.input.len) {
            const line = p.readLine();
            const trimmed = std.mem.trim(u8, line, " \t\r");
            if (trimmed.len == 0) continue;

            // Skip comment lines
            if (trimmed[0] == ';' or trimmed[0] == '#') continue;

            if (trimmed[0] == '[') {
                // Section header: [section] or [a.b.c]
                const close = std.mem.indexOfScalar(u8, trimmed, ']') orelse continue;
                const section = std.mem.trim(u8, trimmed[1..close], " \t");
                if (section.len == 0) continue;
                current = navigateSection(root_expr.data.e_object, section, p.allocator) catch continue;
            } else {
                // key = value  or  key: value
                const sep_idx = findSep(trimmed) orelse continue;
                const key = std.mem.trim(u8, trimmed[0..sep_idx], " \t");
                const raw_val = std.mem.trim(u8, trimmed[sep_idx + 1 ..], " \t");
                if (key.len == 0) continue;

                const val_str = std.mem.trim(u8, stripComment(raw_val), " \t");
                const key_str = try p.allocator.dupe(u8, key);
                const val_expr = try coerce(p.allocator, val_str);

                try current.properties.append(p.allocator, .{
                    .key = Expr.init(E.String, E.String{ .data = key_str }, logger.Loc.Empty),
                    .value = val_expr,
                });
            }
        }

        return root_expr;
    }

    fn readLine(p: *Parser) []const u8 {
        const start = p.pos;
        while (p.pos < p.input.len and p.input[p.pos] != '\n') {
            p.pos += 1;
        }
        const end = p.pos;
        if (p.pos < p.input.len) p.pos += 1; // skip '\n'
        const line = p.input[start..end];
        // Strip trailing '\r'
        if (line.len > 0 and line[line.len - 1] == '\r') return line[0 .. line.len - 1];
        return line;
    }
};

/// Navigate (or create) the nested object for a dotted section name like "a.b.c".
fn navigateSection(root: *E.Object, section: []const u8, allocator: std.mem.Allocator) !*E.Object {
    var current = root;
    var it = std.mem.splitScalar(u8, section, '.');
    while (it.next()) |raw_part| {
        const part = std.mem.trim(u8, raw_part, " \t");
        if (part.len == 0) continue;
        current = try getOrCreateChild(current, part, allocator);
    }
    return current;
}

/// Return (or create) a child object property with the given key.
/// If the key already exists and is an object, returns that object.
/// Otherwise creates a new child object (potentially creating a duplicate key,
/// which is fine — exprToJS uses putMayBeIndex which takes the last value).
fn getOrCreateChild(obj: *E.Object, key: []const u8, allocator: std.mem.Allocator) !*E.Object {
    // Search for an existing object property with this key
    for (obj.properties.slice()) |prop| {
        const k = prop.key orelse continue;
        const v = prop.value orelse continue;
        switch (k.data) {
            .e_string => |s| {
                if (std.mem.eql(u8, s.data, key)) {
                    switch (v.data) {
                        .e_object => |child| return child,
                        else => {}, // exists but not an object — fall through
                    }
                }
            },
            else => {},
        }
    }
    // Not found (or non-object) — create a new child
    const key_str = try allocator.dupe(u8, key);
    const child_expr = Expr.init(E.Object, E.Object{}, logger.Loc.Empty);
    try obj.properties.append(allocator, .{
        .key = Expr.init(E.String, E.String{ .data = key_str }, logger.Loc.Empty),
        .value = child_expr,
    });
    return child_expr.data.e_object;
}

/// Find the first unquoted '=' or ':' separator in a line.
fn findSep(line: []const u8) ?usize {
    var in_q = false;
    var qc: u8 = 0;
    for (line, 0..) |c, i| {
        if (in_q) {
            if (c == qc) in_q = false;
        } else if (c == '"' or c == '\'') {
            in_q = true;
            qc = c;
        } else if (c == '=' or c == ':') {
            return i;
        }
    }
    return null;
}

/// Strip a trailing inline comment (unquoted ';' or '#') from a value.
fn stripComment(raw: []const u8) []const u8 {
    var in_dq = false;
    var in_sq = false;
    var i: usize = 0;
    while (i < raw.len) : (i += 1) {
        const c = raw[i];
        if (c == '"' and !in_sq) {
            in_dq = !in_dq;
        } else if (c == '\'' and !in_dq) {
            in_sq = !in_sq;
        } else if ((c == ';' or c == '#') and !in_dq and !in_sq) {
            return std.mem.trimRight(u8, raw[0..i], " \t");
        }
    }
    return raw;
}

/// Coerce an unquoted value string to the appropriate Expr type.
fn coerce(allocator: std.mem.Allocator, raw: []const u8) !Expr {
    if (raw.len == 0) {
        return Expr.init(E.String, E.String{ .data = "" }, logger.Loc.Empty);
    }

    // Quoted string — strip the surrounding quotes
    if (raw.len >= 2) {
        const f = raw[0];
        const l = raw[raw.len - 1];
        if ((f == '"' and l == '"') or (f == '\'' and l == '\'')) {
            const inner = try allocator.dupe(u8, raw[1 .. raw.len - 1]);
            return Expr.init(E.String, E.String{ .data = inner }, logger.Loc.Empty);
        }
    }

    // null
    if (std.mem.eql(u8, raw, "null")) {
        return Expr.init(E.Null, E.Null{}, logger.Loc.Empty);
    }

    // boolean
    if (std.mem.eql(u8, raw, "true")) {
        return Expr.init(E.Boolean, E.Boolean{ .value = true }, logger.Loc.Empty);
    }
    if (std.mem.eql(u8, raw, "false")) {
        return Expr.init(E.Boolean, E.Boolean{ .value = false }, logger.Loc.Empty);
    }

    // integer
    if (std.fmt.parseInt(i64, raw, 10)) |n| {
        return Expr.init(E.Number, E.Number{ .value = @floatFromInt(n) }, logger.Loc.Empty);
    } else |_| {}

    // float
    if (std.fmt.parseFloat(f64, raw)) |f| {
        return Expr.init(E.Number, E.Number{ .value = f }, logger.Loc.Empty);
    } else |_| {}

    // string fallback
    const s = try allocator.dupe(u8, raw);
    return Expr.init(E.String, E.String{ .data = s }, logger.Loc.Empty);
}

const std = @import("std");
const bun = @import("bun");
const logger = bun.logger;
const js_ast = bun.ast;
const E = js_ast.E;
const Expr = js_ast.Expr;

