pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    var arena: bun.ArenaAllocator = .init(bun.default_allocator);
    defer arena.deinit();
    const allocator = arena.allocator();

    var ast_memory_allocator = bun.handleOom(allocator.create(ast.ASTMemoryAllocator));
    var ast_scope = ast_memory_allocator.enter(allocator);
    defer ast_scope.exit();

    const input_value = callFrame.argument(0);
    if (input_value.isEmptyOrUndefinedOrNull()) {
        return global.throwInvalidArguments("Expected a string to parse", .{});
    }

    var input_slice = try input_value.toSlice(global, bun.default_allocator);
    defer input_slice.deinit();

    bun.analytics.Features.ini_parse += 1;

    const source = &logger.Source.initPathString("input.ini", input_slice.slice());
    const root = ini.INI.parse(source, allocator) catch |err| return switch (err) {
        error.OutOfMemory => |oom| oom,
        else => global.throwValue(global.createSyntaxErrorInstance("INI parse error", .{})),
    };

    return exprToJS(root, global);
}

pub fn stringify(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callFrame.argument(0);

    if (value.isUndefined() or value.isNull()) {
        return .null;
    }

    if (!value.isObject() or value.isArray()) {
        return global.throwInvalidArguments("INI.stringify expects a plain object", .{});
    }

    var builder: wtf.StringBuilder = .init();
    errdefer builder.deinit();

    // Pass 1: write root-level scalar properties
    var wrote_any_scalar = false;
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const val = iter.value;
            if (val.isUndefined() or val.isSymbol() or val.isFunction()) continue;
            // Skip nested plain objects (they become sections in pass 2)
            if (val.isObject() and !val.isArray()) continue;

            if (wrote_any_scalar) builder.append(.lchar, '\n');
            wrote_any_scalar = true;

            builder.append(.string, prop_name);
            builder.append(.latin1, " = ");
            try appendScalar(&builder, global, val);
        }
    }

    // Pass 2: write object properties as [section] headers
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter.deinit();

        while (try iter.next()) |section_name| {
            const section_val = iter.value;
            if (!section_val.isObject() or section_val.isArray()) continue;

            // Section header
            builder.append(.lchar, '\n');
            builder.append(.lchar, '[');
            builder.append(.string, section_name);
            builder.append(.latin1, "]\n");

            var wrote_any_in_section = false;
            var section_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
                global,
                try section_val.toObject(global),
            );
            defer section_iter.deinit();

            while (try section_iter.next()) |key_name| {
                const kval = section_iter.value;
                if (kval.isUndefined() or kval.isSymbol() or kval.isFunction()) continue;
                if (kval.isObject() and !kval.isArray()) {
                    return global.throw("INI.stringify: object nesting exceeds maximum depth of 1", .{});
                }

                if (wrote_any_in_section) builder.append(.lchar, '\n');
                wrote_any_in_section = true;

                builder.append(.string, key_name);
                builder.append(.latin1, " = ");
                try appendScalar(&builder, global, kval);
            }
        }
    }

    return try builder.toString(global);
}

/// Append a scalar JS value to the builder as an INI value.
fn appendScalar(builder: *wtf.StringBuilder, global: *jsc.JSGlobalObject, value: JSValue) bun.JSError!void {
    const unwrapped = try value.unwrapBoxedPrimitive(global);

    if (unwrapped.isNull()) {
        builder.append(.latin1, "null");
        return;
    }

    if (unwrapped.isBoolean()) {
        builder.append(.latin1, if (unwrapped.asBoolean()) "true" else "false");
        return;
    }

    if (unwrapped.isInt32()) {
        builder.append(.int, unwrapped.asInt32());
        return;
    }

    if (unwrapped.isNumber()) {
        builder.append(.double, unwrapped.asNumber());
        return;
    }

    if (unwrapped.isString()) {
        const str = try unwrapped.toBunString(global);
        defer str.deref();
        appendQuotedString(builder, str);
        return;
    }

    // For arrays and other values, convert to string
    const str = try unwrapped.toBunString(global);
    defer str.deref();
    appendQuotedString(builder, str);
}

/// Append a possibly-quoted string value. We always quote to ensure safe round-trips.
fn appendQuotedString(builder: *wtf.StringBuilder, str: bun.String) void {
    // If the string is a simple "safe" value (no special chars), write unquoted.
    // Otherwise wrap in double quotes with minimal escaping.
    if (strIsSafe(str)) {
        builder.append(.string, str);
        return;
    }

    builder.append(.lchar, '"');
    var i: usize = 0;
    while (i < str.length()) : (i += 1) {
        const c = str.charAt(i);
        switch (c) {
            '"' => {
                builder.append(.lchar, '\\');
                builder.append(.lchar, '"');
            },
            '\\' => {
                builder.append(.lchar, '\\');
                builder.append(.lchar, '\\');
            },
            '\n' => {
                builder.append(.lchar, '\\');
                builder.append(.lchar, 'n');
            },
            '\r' => {
                builder.append(.lchar, '\\');
                builder.append(.lchar, 'r');
            },
            '\t' => {
                builder.append(.lchar, '\\');
                builder.append(.lchar, 't');
            },
            else => builder.append(.uchar, c),
        }
    }
    builder.append(.lchar, '"');
}

/// Returns true if a string value is safe to write without quoting in INI.
fn strIsSafe(str: bun.String) bool {
    if (str.isEmpty()) return false;
    const len = str.length();

    // Leading/trailing whitespace requires quoting
    switch (str.charAt(0)) {
        ' ', '\t' => return false,
        else => {},
    }
    switch (str.charAt(len - 1)) {
        ' ', '\t' => return false,
        else => {},
    }

    // Check for characters that would be misinterpreted
    var i: usize = 0;
    while (i < len) : (i += 1) {
        switch (str.charAt(i)) {
            '=', ':', ';', '#', '\n', '\r', '"', '\'', '[', ']', '\\' => return false,
            else => {},
        }
    }

    // Reserved words must be quoted to preserve their string meaning
    const keywords = &.{ "true", "false", "null" };
    inline for (keywords) |kw| {
        if (str.eqlComptime(kw)) return false;
    }

    return true;
}

/// Convert an Expr AST node to a JS value.
fn exprToJS(expr: Expr, global: *jsc.JSGlobalObject) bun.JSError!jsc.JSValue {
    switch (expr.data) {
        .e_null => return .null,
        .e_boolean => |boolean| return .jsBoolean(boolean.value),
        .e_number => |number| return .jsNumber(number.value),
        .e_string => |str| return str.toJS(bun.default_allocator, global),
        .e_array => |arr| {
            var js_arr = try JSValue.createEmptyArray(global, arr.items.len);
            for (arr.slice(), 0..) |item, _i| {
                const i: u32 = @intCast(_i);
                const v = try exprToJS(item, global);
                try js_arr.putIndex(global, i, v);
            }
            return js_arr;
        },
        .e_object => |obj| {
            var js_obj = JSValue.createEmptyObject(global, obj.properties.len);
            for (obj.properties.slice()) |prop| {
                const key_expr = prop.key orelse continue;
                const val_expr = prop.value orelse continue;
                const v = try exprToJS(val_expr, global);
                const key_js = try exprToJS(key_expr, global);
                const key_str = try key_js.toBunString(global);
                defer key_str.deref();
                try js_obj.putMayBeIndex(global, &key_str, v);
            }
            return js_obj;
        },
        else => return .js_undefined,
    }
}

