    }

    if (unwrapped.isBoolean()) {
        builder.append(.latin1, if (unwrapped.asBoolean()) "true" else "false");
        return;
    }

    if (unwrapped.isInt32()) {
        builder.append(.int, unwrapped.asInt32());
        return;
    }

    if (unwrapped.isNumber()) {
        builder.append(.double, unwrapped.asNumber());
        return;
    }

    if (unwrapped.isString()) {
        const str = try unwrapped.toBunString(global);
        defer str.deref();
        appendQuotedString(builder, str);
        return;
    }

    // For arrays and other values, convert to string
    const str = try unwrapped.toBunString(global);
    defer str.deref();
    appendQuotedString(builder, str);
}

/// Append a possibly-quoted string value. We always quote to ensure safe round-trips.
fn appendQuotedString(builder: *wtf.StringBuilder, str: bun.String) void {
    // If the string is a simple "safe" value (no special chars), write unquoted.
    // Otherwise wrap in double quotes with minimal escaping.
    if (strIsSafe(str)) {
        builder.append(.string, str);
        return;
    }

    builder.append(.lchar, '"');
    var i: usize = 0;
    while (i < str.length()) : (i += 1) {
        const c = str.charAt(i);
        switch (c) {
            '"' => {
                builder.append(.lchar, '\\');
                builder.append(.lchar, '"');
            },
            '\\' => {
                builder.append(.lchar, '\\');
                builder.append(.lchar, '\\');
            },
            '\n' => {
                builder.append(.lchar, '\\');
                builder.append(.lchar, 'n');
            },
            '\r' => {
                builder.append(.lchar, '\\');
                builder.append(.lchar, 'r');
            },
            '\t' => {
                builder.append(.lchar, '\\');
                builder.append(.lchar, 't');
            },
            else => builder.append(.uchar, c),
        }
    }
    builder.append(.lchar, '"');
}

/// Returns true if a string value is safe to write without quoting in INI.
fn strIsSafe(str: bun.String) bool {
    if (str.isEmpty()) return false;
    const len = str.length();

    // Leading/trailing whitespace requires quoting
    switch (str.charAt(0)) {
        ' ', '\t' => return false,
        else => {},
    }
    switch (str.charAt(len - 1)) {
        ' ', '\t' => return false,
        else => {},
    }

    // Check for characters that would be misinterpreted
    var i: usize = 0;
    while (i < len) : (i += 1) {
        switch (str.charAt(i)) {
            '=', ':', ';', '#', '\n', '\r', '"', '\'', '[', ']', '\\' => return false,
            else => {},
        }
    }

    // Reserved words must be quoted to preserve their string meaning
    const keywords = &.{ "true", "false", "null" };
    inline for (keywords) |kw| {
        if (str.eqlComptime(kw)) return false;
    }

    return true;
}

/// Convert an Expr AST node to a JS value.
fn exprToJS(expr: Expr, global: *jsc.JSGlobalObject) bun.JSError!jsc.JSValue {
    switch (expr.data) {
        .e_null => return .null,
        .e_boolean => |boolean| return .jsBoolean(boolean.value),
        .e_number => |number| return .jsNumber(number.value),
        .e_string => |str| return str.toJS(bun.default_allocator, global),
        .e_array => |arr| {
            var js_arr = try JSValue.createEmptyArray(global, arr.items.len);
            for (arr.slice(), 0..) |item, _i| {
                const i: u32 = @intCast(_i);
                const v = try exprToJS(item, global);
                try js_arr.putIndex(global, i, v);
            }
            return js_arr;
        },
        .e_object => |obj| {
            var js_obj = JSValue.createEmptyObject(global, obj.properties.len);
            for (obj.properties.slice()) |prop| {
                const key_expr = prop.key orelse continue;
                const val_expr = prop.value orelse continue;
                const v = try exprToJS(val_expr, global);
                const key_js = try exprToJS(key_expr, global);
                const key_str = try key_js.toBunString(global);
                defer key_str.deref();
                try js_obj.putMayBeIndex(global, &key_str, v);
            }
            return js_obj;
        },
        else => return .js_undefined,
    }
}

