import { describe, expect, test } from "bun:test";

// Tests for the public Bun.INI API (parse + stringify).
// The internal package-manager INI parser is tested in ini.test.ts.

describe("Bun.INI", () => {
  test("is an object with parse and stringify", () => {
    expect(typeof Bun.INI).toBe("object");
    expect(typeof Bun.INI.parse).toBe("function");
    expect(typeof Bun.INI.stringify).toBe("function");
  });
});

describe("Bun.INI.parse", () => {
  test("empty string returns empty object", () => {
    expect(Bun.INI.parse("")).toEqual({});
  });

  test("simple key=value pairs", () => {
    const result = Bun.INI.parse("name = Alice\nage = 30");
    expect(result).toEqual({ name: "Alice", age: 30 });
  });

  test("colon separator", () => {
    const result = Bun.INI.parse("key: value");
    expect(result).toEqual({ key: "value" });
  });

  test("boolean coercion", () => {
    const result = Bun.INI.parse("enabled = true\ndisabled = false");
    expect(result).toEqual({ enabled: true, disabled: false });
  });

  test("null coercion", () => {
    const result = Bun.INI.parse("nothing = null");
    expect(result).toEqual({ nothing: null });
  });

  test("integer coercion", () => {
    const result = Bun.INI.parse("port = 5432\ncount = 0");
    expect(result).toEqual({ port: 5432, count: 0 });
  });

  test("float coercion", () => {
    const result = Bun.INI.parse("ratio = 3.14");
    expect(result).toEqual({ ratio: 3.14 });
  });

  test("quoted string preserves as string", () => {
    const result = Bun.INI.parse(`greeting = "hello world"`);
    expect(result).toEqual({ greeting: "hello world" });
  });

  test("single-quoted string preserves as string", () => {
    const result = Bun.INI.parse(`greeting = 'hello world'`);
    expect(result).toEqual({ greeting: "hello world" });
  });

  test("quoted 'true' stays as string, not boolean", () => {
    const result = Bun.INI.parse(`val = "true"`);
    expect(result).toEqual({ val: "true" });
  });

  test("semicolon comment lines are ignored", () => {
    const ini = `
; This is a comment
name = Bob
`;
    expect(Bun.INI.parse(ini)).toEqual({ name: "Bob" });
  });

  test("hash comment lines are ignored", () => {
    const ini = `
# This is a comment
name = Bob
`;
    expect(Bun.INI.parse(ini)).toEqual({ name: "Bob" });
  });

  test("inline semicolon comment stripped from value", () => {
    const result = Bun.INI.parse("host = localhost ; database host");
    expect(result).toEqual({ host: "localhost" });
  });

  test("inline hash comment stripped from value", () => {
    const result = Bun.INI.parse("host = localhost # database host");
    expect(result).toEqual({ host: "localhost" });
  });

  test("inline comment not stripped from quoted string", () => {
    const result = Bun.INI.parse(`msg = "hello ; world"`);
    expect(result).toEqual({ msg: "hello ; world" });
  });

  test("section creates nested object", () => {
    const ini = `
name = global

[database]
host = localhost
port = 5432
`;
    expect(Bun.INI.parse(ini)).toEqual({
      name: "global",
      database: { host: "localhost", port: 5432 },
    });
  });

  test("multiple sections", () => {
    const ini = `
[server]
host = 0.0.0.0
port = 8080

[database]
host = localhost
port = 5432
`;
    expect(Bun.INI.parse(ini)).toEqual({
      server: { host: "0.0.0.0", port: 8080 },
      database: { host: "localhost", port: 5432 },
    });
  });

  test("dotted section name creates nested objects", () => {
    const ini = `
[database.primary]
host = db1.example.com

[database.replica]
host = db2.example.com
`;
    expect(Bun.INI.parse(ini)).toEqual({
      database: {
        primary: { host: "db1.example.com" },
        replica: { host: "db2.example.com" },
      },
    });
  });

  test("deeply dotted section", () => {
    const ini = `
[a.b.c]
key = value
`;
    expect(Bun.INI.parse(ini)).toEqual({
      a: { b: { c: { key: "value" } } },
    });
  });

  test("windows-style CRLF line endings", () => {
    const result = Bun.INI.parse("name = Alice\r\nage = 30\r\n");
    expect(result).toEqual({ name: "Alice", age: 30 });
  });

  test("blank lines are ignored", () => {
    const ini = `

name = Alice

age = 30

`;
    expect(Bun.INI.parse(ini)).toEqual({ name: "Alice", age: 30 });
  });

  test("throws on non-string input", () => {
    expect(() => Bun.INI.parse(undefined as any)).toThrow();
    expect(() => Bun.INI.parse(null as any)).toThrow();
  });
});

describe("Bun.INI.stringify", () => {
  test("simple scalars", () => {
    const result = Bun.INI.stringify({ name: "Alice", age: 30 });
    expect(result).toContain("name = Alice");
    expect(result).toContain("age = 30");
  });

  test("boolean values", () => {
    const result = Bun.INI.stringify({ enabled: true, disabled: false });
    expect(result).toContain("enabled = true");
    expect(result).toContain("disabled = false");
  });

  test("null value", () => {
    const result = Bun.INI.stringify({ nothing: null });
    expect(result).toContain("nothing = null");
  });

  test("section from nested object", () => {
    const result = Bun.INI.stringify({
      database: { host: "localhost", port: 5432 },
    });
    expect(result).toContain("[database]");
    expect(result).toContain("host = localhost");
    expect(result).toContain("port = 5432");
  });

  test("scalars come before sections", () => {
    const result = Bun.INI.stringify({
      name: "my-app",
      database: { host: "localhost" },
    });
    const namePos = result.indexOf("name =");
    const sectionPos = result.indexOf("[database]");
    expect(namePos).toBeLessThan(sectionPos);
  });

  test("throws on nesting deeper than 1", () => {
    expect(() =>
      Bun.INI.stringify({
        section: { nested: { too: "deep" } },
      }),
    ).toThrow();
  });

  test("null/undefined returns null", () => {
    expect(Bun.INI.stringify(null as any)).toBeNull();
    expect(Bun.INI.stringify(undefined as any)).toBeNull();
  });

  test("string values needing quotes are quoted", () => {
    const result = Bun.INI.stringify({ msg: "hello = world" });
    // The value contains '=' so it must be quoted
    expect(result).toContain('"hello = world"');
  });

  test("round-trip parse(stringify(x)) === x for simple objects", () => {
    const original = {
      name: "my-app",
      version: 2,
      enabled: true,
      database: {
        host: "localhost",
        port: 5432,
      },
    };
    const stringified = Bun.INI.stringify(original);
    const parsed = Bun.INI.parse(stringified) as typeof original;

    expect(parsed.name).toBe("my-app");
    expect(parsed.version).toBe(2);
    expect(parsed.enabled).toBe(true);
    expect((parsed.database as any).host).toBe("localhost");
    expect((parsed.database as any).port).toBe(5432);
  });
});

