1	/// Self-contained INI parser that returns a js_ast.Expr tree.
2	/// Does NOT depend on src/ini.zig (the internal package-manager parser).
3	///
4	/// Supported syntax:
5	///   [section]          section header
6	///   [a.b.c]            dotted section names (creates nested objects)
7	///   key = value        key/value assignment
8	///   key: value         colon-style assignment
9	///   ; comment          semicolon comment
10	///   # comment          hash comment
11	///   "quoted value"     double-quoted string (quotes stripped)
12	///   'quoted value'     single-quoted string (quotes stripped)
13	///
14	/// Unquoted value coercion:
15	///   true / false       boolean
16	///   null               null
17	///   integer            number (e.g. 42)
18	///   float              number (e.g. 3.14)
19	///   other              string
20	
21	pub const INI = struct {
22	    pub fn parse(source_: *const logger.Source, allocator: std.mem.Allocator) !Expr {
23	        if (source_.contents.len == 0) {
24	            return Expr.init(E.Object, E.Object{}, logger.Loc.Empty);
25	        }
26	        var p: Parser = .{ .allocator = allocator, .input = source_.contents };
27	        return p.run();
28	    }
29	};
30	
31	const Parser = struct {
32	    allocator: std.mem.Allocator,
33	    input: []const u8,
34	    pos: usize = 0,
35	
36	    fn run(p: *Parser) !Expr {
37	        const root_expr = Expr.init(E.Object, E.Object{}, logger.Loc.Empty);
38	        var current: *E.Object = root_expr.data.e_object;
39	
40	        while (p.pos < p.input.len) {
41	            const line = p.readLine();
42	            const trimmed = std.mem.trim(u8, line, " \t\r");
